 8	import { VDDKDetailsItem } from 'src/modules/Providers/views/details/components/DetailsSection/components/VDDKDetailsItem';
 9	import { getVSphereProviderWebUILink } from 'src/modules/Providers/views/details/components/DetailsSection/utils/getVSphereProviderWebUILink';
10	import { ForkliftTrans, useForkliftTranslation } from 'src/utils/i18n';
11	
12	import CreatedAtDetailsItem from '@components/DetailItems/CreatedAtDetailItem';
13	import NameDetailsItem from '@components/DetailItems/NameDetailItem';
14	import NamespaceDetailsItem from '@components/DetailItems/NamespaceDetailItem';
15	import OwnerDetailsItem from '@components/DetailItems/OwnerDetailItem';
