23	  const { inventory, permissions, provider } = data;
24	
25	  if (!provider || !permissions) return null;
26	
27	  return (
28	    <ModalHOC>
29	      <DescriptionList
30	        columnModifier={{
31	          default: '2Col',
32	        }}
33	      >
34	        <TypeDetailsItem resource={provider} />
