36	          testId="product-detail-item"
37	          title={t('Product')}
38	          content={
39	            (inventory as VSphereProvider)?.product || (
40	              <span className="text-muted">{t('Empty')}</span>
41	            )
42	          }
43	          helpContent={t(`VMware only: vSphere product name.`)}
44	          crumbs={['Inventory', 'providers', provider.spec?.type ?? '', '[UID]']}
45	        />
46	        <NameDetailsItem resource={provider} />
47	        <ExternalManagementLinkDetailsItem
48	          resource={provider}
49	          canPatch={permissions.canPatch}
50	          webUILinkText={t(`VMware vSphere UI`)}
51	          webUILink={getVSphereProviderWebUILink(provider)}
