54	          resource={provider}
55	          canPatch={permissions.canPatch}
56	          helpContent={
57	            <ForkliftTrans>
58	              URL of the API endpoint of the vCenter on which the source VM is mounted. Ensure that
59	              the URL includes the sdk path, usually <strong>/sdk</strong>.<br />
60	              <br />
61	              For example: <strong>https://vCenter-host-example.com/sdk</strong>.<br />
62	              <br />
63	              If a certificate for FQDN is specified, the value of this field needs to match the
64	              FQDN in the certificate.
65	            </ForkliftTrans>
66	          }
67	        />
68	        <NamespaceDetailsItem resource={provider} />
69	        <CredentialsDetailsItem resource={provider} />
70	        <CreatedAtDetailsItem resource={provider} />
71	        <OwnerDetailsItem resource={provider} />
72	        <VDDKDetailsItem resource={provider} canPatch={permissions.canPatch} />
73	      </DescriptionList>
74	    </ModalHOC>
75	  );
76	};
77	
78	export default VSphereDetailsSection;

